import type { WithRef } from '@andes/common';
import type {
  ChangeEventHandler,
  FocusEventHandler,
  FunctionComponent,
  InputHTMLAttributes,
  TextareaHTMLAttributes,
  ReactElement,
  ReactNode,
  ClipboardEvent,
  ChangeEvent,
} from 'react';

type Token = {
  multiple?: boolean;
  optional?: boolean;
  pattern: RegExp;
};

type Mask = {
  eager?: boolean;
  mask: string;
  postProcess?: (value: string) => string;
  preProcess?: (value: string) => string;
  tokens: Record<string, Token>;
};

type DeprecatedModifiers = 'warning';

type LabelOrSrLabel =
  | {
      /** Text to display as label. */
      label: string;

      /**  Input label for screen readers. */
      srLabel?: string;
    }
  | {
      /** Text to display as label. */
      label?: string;

      /**  Input label for screen readers. */
      srLabel: string;
    };

type CommonProps = {
  /**
   * Whether the field should be focused automatically.
   *
   * @default false
   */
  autoFocus?: boolean;

  /** Default value for field (uncontrolled behavior). */
  defaultValue?: string;

  /**
   * Whether the field should be disabled.
   *
   * @default false
   */
  disabled?: boolean;

  /** Text or node to display as helper to the user (or as error message). */
  helper?: ReactNode;

  /** Component identifier. */
  id?: string;

  /**
   * Maximum number of characters permitted in the field.
   * Used when `countdown` is set.
   *
   * @default 120
   */
  maxLength?: number | string;

  /** Modifier to apply different styles of the textfield. */
  modifier?:
    | DeprecatedModifiers
    | 'caution'
    | 'completed'
    | 'error'
    | 'indeterminate'
    | 'readonly';

  /** Placeholder of the field. */
  placeholder?: string;

  /** Value for field (controlled behavior). */
  value?: number | string;
};

type TextFieldContainerSpecificProps = TextFieldSpecificProps &
  WithRef<HTMLDivElement>;

type TextFieldPropsInherited = CommonProps & {
  // Props inherited from CommonProps

  /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation} */
  autoFocus?: CommonProps['autoFocus'];

  /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation} */
  defaultValue?: CommonProps['defaultValue'];

  /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation} */
  disabled?: CommonProps['disabled'];

  /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation} */
  helper?: CommonProps['helper'];

  /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation} */
  id?: CommonProps['id'];

  /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation} */
  maxLength?: CommonProps['maxLength'];

  /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation} */
  modifier?: CommonProps['modifier'];

  /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation} */
  placeholder?: CommonProps['placeholder'];

  /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation} */
  value?: CommonProps['value'];
};

type InputPropsMultiline =
  | {
      /**
       * {@link https://developer.mozilla.org/en-US/docs/Web/HTML/Element/input#attributes | Attributes } applied to the input element.
       *
       * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
       * @default {}
       */
      inputProps?: InputHTMLAttributes<HTMLInputElement>;

      /**
       * Whether the field should act as textarea.
       *
       * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
       * @default false
       */
      multiline?: boolean;
    }
  | {
      /**
       * {@link https://developer.mozilla.org/en-US/docs/Web/HTML/Element/textarea#attributes | Attributes } applied to the textarea element.
       *
       * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
       * @default {}
       */
      inputProps?: TextareaHTMLAttributes<HTMLTextAreaElement>;

      /**
       * Whether the field should act as textarea.
       *
       * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
       * @default false
       */
      multiline: boolean;
    };

type TextFieldSpecificProps = InputPropsMultiline &
  LabelOrSrLabel &
  TextFieldPropsInherited & {
    /**
     * Whether the field should be centered.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
     * @default false
     */
    centered?: boolean;

    /**
     * Custom children component, could be a `Checkbox`, `Button`, `Icon` or `Tooltip` component.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
     */
    children?: ReactNode;

    /**
     * Custom class.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
     */
    className?: string;

    /**
     * Whether the field should display a clear button.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
     * @default false
     */
    clear?: boolean;

    /**
     * Whether the field should display a character counter.
     * Best suited when set to `multiline`, and works with `maxLength`.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
     * @default false
     */
    countdown?: boolean;

    /**
     * Whether to force the focus on textfield.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
     * @default false
     */
    focus?: boolean;

    /**
     * Callback that executes when `blur` event triggers.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
     */
    onBlur?: FocusEventHandler<HTMLInputElement | HTMLTextAreaElement>;

    /**
     * Callback that executes when the content of the input changes.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
     */
    onChange?: ChangeEventHandler<HTMLInputElement | HTMLTextAreaElement>;

    /**
     * Callback that executes when `focus` event triggers.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
     */
    onFocus?: FocusEventHandler<HTMLInputElement | HTMLTextAreaElement>;

    /**
     * Callback that executes when the user interface on the input changes.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
     */
    onInput?: ChangeEventHandler<HTMLInputElement | HTMLTextAreaElement>;

    /**
     * Text to display as prefix.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
     */
    prefix?: string;

    /**
     * Native `rows` attribute, used when `multiline` is set.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
     * @default 1
     */
    rows?: number | string;

    /**
     * Whether to force the select over the textfield.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
     * @default false
     */
    select?: boolean;

    /**
     * Determines the size of the input
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
     * @default 'large'
     */
    size?: 'large' | 'medium';

    /**
     * Text to display as suffix.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
     */
    suffix?: string;

    /**
     * Width in percentage of 256px.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#textfield-1 | Documentation}
     */
    width?: 25 | 50 | 75 | 100 | 150 | 200;
  };

type Item = {
  icon?: () => ReactElement;
  title: string;
};

type Items = {
  content: Array<Item>;
  onClick?: (item: Item) => void;
};

type SplitTextFieldSpecificProps = LabelOrSrLabel &
  WithRef<HTMLDivElement> & {
    /**
     * Custom children component, could be a `Text`, `Progress indicator` or `Tooltip` component.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#splittextfield-props | Documentation}
     */
    children?: ReactNode;

    /**
     * Custom class.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#splittextfield-props | Documentation}
     */
    className?: string;

    /**
     * Index of the default element selected in the menu.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#splittextfield-props | Documentation}
     * @default 0
     */
    defaultSelection?: number;

    /**
     * {@link https://developer.mozilla.org/en-US/docs/Web/HTML/Element/input#attributes | Attributes } applied to the input element.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#splittextfield-props | Documentation}
     * @default {}
     */
    inputProps?: InputHTMLAttributes<HTMLInputElement>;

    /**
     * List of options to show inside the menu.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#splittextfield-props | Documentation}
     */
    list?: Items;

    /**
     * Callback that executed when the dropdown is opened.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#splittextfield-props | Documentation}
     */
    onDropdownOpen?: () => void;

    /**
     * Icon to show in the dropdown button.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#splittextfield-props | Documentation}
     */
    splitIcon?: ReactNode;

    /**
     * Label to show in the dropdown button.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#splittextfield-props | Documentation}
     */
    splitLabel?: ReactNode;

    /**
     * Position according to the field to show the menu.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#splittextfield-props | Documentation}
     * @default 'left'
     */
    splitPosition?: 'left' | 'right';
  };

type CodeInputAndNumericInheritedProps = LabelOrSrLabel &
  Omit<CommonProps, 'defaultValue' | 'maxLength' | 'placeholder' | 'value'> & {
    // Props inherited from CommonProps

    /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#codeinput-props | Documentation} */
    disabled?: CommonProps['disabled'];

    /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#codeinput-props | Documentation} */
    helper?: CommonProps['helper'];

    /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#codeinput-props | Documentation} */
    id?: CommonProps['id'];

    /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#codeinput-props | Documentation} */
    modifier?: CommonProps['modifier'];
  };

type CodeInputProps = CodeInputAndNumericInheritedProps &
  WithRef<HTMLDivElement> & {
    /**
     * Whether the fields and respective texts should be centered or positioned left.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#codeinput-props | Documentation}
     * @default false
     */
    centered?: boolean;

    /**
     * Custom class.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#codeinput-props | Documentation}
     */
    className?: string;

    /**
     * Default value for field (uncontrolled behavior).
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#codeinput-props | Documentation}
     */
    defaultValue?: Array<string> | string;

    /**
     * Number of digits.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#codeinput-props | Documentation}
     * @default 1
     */
    digits?: number;

    /**
     * Number of the digit to focus, or if `true` is passed, the 1st element will be focused.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#codeinput-props | Documentation}
     * @default 0
     */
    focus?: boolean | number;

    /**
     * Modifier to add the corresponding styling and behavior.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#codeinput-props | Documentation}
     */
    modifier?: 'completed' | 'error';

    /**
     * Callback that executes when the content of the input changes.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#codeinput-props | Documentation}
     */
    onChange?: (
      event: ChangeEvent<HTMLInputElement | HTMLTextAreaElement>,
      values: Array<number | string> | Array<number> | Array<string>,
    ) => void;

    /**
     * Callback that triggers when a value is copied.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#codeinput-props | Documentation}
     */
    onPaste?: (
      event: ClipboardEvent<HTMLInputElement>,
      newValues: Array<number | string> | Array<number> | Array<string>,
    ) => void;

    /**
     * Whether the field should allow only numbers without any special characters.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#codeinput-props | Documentation}
     * @default false
     */
    strict?: boolean;

    /**
     * Value for field (controlled behavior).
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#codeinput-props | Documentation}
     */
    value?: Array<string> | string;
  };

type PasswordInheritedProps = LabelOrSrLabel &
  Omit<CommonProps, 'disabled' | 'inputProps'> & {
    // Props inherited from CommonProps

    /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#password-props | Documentation} */
    autoFocus?: CommonProps['autoFocus'];

    /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#password-props | Documentation} */
    defaultValue?: CommonProps['defaultValue'];

    /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#password-props | Documentation} */
    helper?: CommonProps['helper'];

    /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#password-props | Documentation} */
    id?: CommonProps['id'];

    /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#password-props | Documentation} */
    maxLength?: CommonProps['maxLength'];

    /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#password-props | Documentation} */
    modifier?: CommonProps['modifier'];

    /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#password-props | Documentation} */
    placeholder?: CommonProps['placeholder'];

    /** @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#password-props | Documentation} */
    value?: CommonProps['value'];
  };

type PasswordSpecificProps = PasswordInheritedProps &
  WithRef<HTMLDivElement> & {
    /**
     * Custom class.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#password-props | Documentation}
     */
    className?: string;

    /**
     * {@link https://developer.mozilla.org/en-US/docs/Web/HTML/Element/input#attributes | Attributes } applied to the input element.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#password-props | Documentation}
     */
    inputProps?: InputHTMLAttributes<HTMLInputElement>;

    /**
     * Modifier for styles of the textfield.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#password-props | Documentation}
     */
    modifier?: 'completed' | 'error' | 'indeterminate';

    /**
     * Callback that executes when `blur` event triggers.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#password-props| Documentation}
     */
    onBlur?: FocusEventHandler<HTMLInputElement>;

    /**
     * Callback that executes when the content of the input changes.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#password-props| Documentation}
     */
    onChange?: ChangeEventHandler<HTMLInputElement>;

    /**
     * Callback that executes when show password button is clicked.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#password-props | Documentation}
     */
    onClickShowPassword?: () => void;

    /**
     * Callback that executes when `focus` event triggers.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#password-props | Documentation}
     */
    onFocus?: FocusEventHandler<HTMLInputElement>;

    /**
     * If `true` it enables the show/hide password feature.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield#password-props | Documentation}
     * @default false
     */
    showHide?: boolean;
  };

type NumericProps = CodeInputProps;

type PasswordProps = PasswordSpecificProps & Record<string, unknown>;

type SplitTextfieldProps = Omit<TextFieldPropsInherited, 'maxLength'> &
  Pick<TextFieldSpecificProps, 'label' | 'onChange' | 'onFocus' | 'srLabel'> &
  Record<string, unknown> &
  SplitTextFieldSpecificProps;

type TextFieldProps = Record<string, unknown> & TextFieldContainerSpecificProps;

/**
 * Code Input textfield.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/258d8b-textfield/b/26f535 | UI Specs}
 * @example
 * import { CodeInput } from '@andes/textfield';
 *
 * const MyComponent = () => (
 *   <CodeInput
 *    id="code-input-test"
 *    label="Personal ID"
 *    digits={4}
 *    helper="Some hint to help the user"
 *   />
 * );
 */
export const CodeInput: FunctionComponent<CodeInputProps>;

/**
 * Password textfield.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/258d8b-textfield/b/26f535 | UI Specs}
 * @example
 * import { Password } from '@andes/textfield';
 *
 * const MyComponent = () => (
 *   <Password
 *    className="demo-textfield"
 *    label="Clave"
 *    placeholder="Placeholder"
 *   />
 * );
 */
export const Password: FunctionComponent<PasswordProps>;

/**
 * SplitTextfield.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/258d8b-textfield/b/26f535 | UI Specs}
 * @example
 * import { SplitTextfield } from '@andes/textfield';
 *
 * const MyComponent = () => {
 *   const splitListItems = [
 *    { title: 'Opción 1' },
 *    { title: 'Opción 2' },
 *    { title: 'Opción 3' },
 *    { title: 'Opción 4' },
 *  ];
 *
 *  return (
 *    <SplitTextfield
 *      className="demo-split-textfield"
 *      label="Main label"
 *      placeholder="Placeholder"
 *      list={{content: splitListItems}}
 *   />
 *  );
 * };
 */
export const SplitTextfield: FunctionComponent<SplitTextfieldProps>;

/**
 * Allows the user to enter and edit text values.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/textfield | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/258d8b-textfield/b/26f535 | UI Specs}
 * @example
 * import { TextField } from '@andes/textfield';
 *
 * const MyComponent = () => (
 *   <TextField label="Phone number" helper="Ej. (11) 4790-533" placeholder="Enter phone number" />
 * );
 */
export const TextField: FunctionComponent<TextFieldProps>;

export type SplitTextFieldOptionItem = Item;
export type TextfieldMask = Mask;
